    public function get_user($id)
    {
        $query = $this->db->placehold("
            SELECT 
                *,
                date_skip_cr_visit < CURRENT_TIMESTAMP as accept_reject_orders
            FROM __users
            WHERE id = ?
        ", (int)$id);
        $this->db->query($query);

        if ($result = $this->db->result()) {

            if (file_exists(__DIR__ . '/../lib/autoloader.php')) {
                require_once __DIR__ . '/../lib/autoloader.php';
                (new UsersAddressService())->addUserAddressesToUser($result);
            }

            $result->registration_address = $this->get_registration_address($result);

            $result->loan_history = empty($result->loan_history) ? [] : json_decode($result->loan_history);

            usort($result->loan_history, function ($a, $b) {
                return Carbon::parse($b->date)->timestamp - Carbon::parse($a->date)->timestamp;
            });

            foreach ($result->loan_history as $loan) {
                $paymentDate = Carbon::parse($loan->plan_close_date);
                $daysOverdue = $paymentDate->isFuture() ? 0 : $paymentDate->diffInDays(Carbon::now());

                $loan->days_overdue = $daysOverdue;
                $loan->asp = !empty($this->getZaimListAsp($loan->number, $id));
            }
        }
        
        return $result;
    }

