    public function get_passport_user($passport, $site_id,  $user_id = null)
    {
        $passport = str_replace(array('-', ' '), '', $passport);
        $var1 = $passport;
        $var2 = substr($passport, 0, 4).'-'.substr($passport, 4, 6);
        $var3 = substr($passport, 0, 2).' '.substr($passport, 2, 2).' '.substr($passport, 4, 6);
        $var4 = substr($passport, 0, 4).' '.substr($passport, 4, 6);

        $query = $this->db->placehold("
            SELECT id FROM __users 
            WHERE (
                passport_serial = ? 
                or passport_serial = ?
                or passport_serial = ?
                or passport_serial = ?
            ) AND site_id = ? 
            " . ($user_id ? " AND id != ?" : '') . "
            LIMIT 1
        ", $var1, $var2, $var3, $var4, $site_id, (int)$user_id);
        $this->db->query($query);

        return $this->db->result('id');
    }

