               $firstMissingDateSelect
               $last_call_filter_query
               $last_comment_query
            FROM __users u 
            LEFT JOIN s_time_zones tz ON tz.time_zone_id = u.timezone_id
            LEFT JOIN s_user_data is_rejected_nk ON is_rejected_nk.user_id = u.id AND is_rejected_nk.`key` = 'is_rejected_nk'
            WHERE 1
                $id_filter
                $site_id_filter
                $search_filter
                $missing_filter
                $missing_status_filter
                $missing_manager_filter
                $missing_date_from_filter
                $missing_date_to_filter
                $date_from_filter
                $date_to_filter
                $completed_filter
                $keyword_filter
                $call_status_search_filter
                $continue_order_search_filter
                $stage_in_contact_search_filter
                $uid_filter
                $exclude_duplicates
                $first_missings_filter

                $search_having
            
            ORDER BY $sort
            $sql_limit
        ");

        $this->db->query($query);
        if ($results = $this->db->results()) {
            foreach ($results as $result) {
                $result->loan_history = empty($result->loan_history) ? array() : json_decode($result->loan_history);
            }
        }

        if ($this->is_developer) {
// фио+тел+дата заявки
//    echo __FILE__.' '.__LINE__.'<br /><pre>';var_dump($query);echo '</pre><hr />';
        }
        return $results;
    }

