    public function getOrgSwitchData(array $userIds): array
    {
        if (empty($userIds)) {
            return [];
        }

        $sql = $this->db->placehold("
            SELECT
                so_new.user_id,
                so_old.organization_id as old_org_id,
                old_org.short_name as old_org_name,
                so_new.organization_id as new_org_id,
                new_org.short_name as new_org_name,
                so_new.date as switch_date
            FROM s_orders so_new
            INNER JOIN s_order_data od_parent
                ON od_parent.order_id = so_new.id
                AND od_parent.`key` = 'order_org_switch_parent_order_id'
            INNER JOIN s_orders so_old
                ON so_old.id = od_parent.value
            INNER JOIN s_order_data od_result
                ON od_result.order_id = so_old.id
                AND od_result.`key` = 'order_org_switch_result'
                AND od_result.value LIKE 'SUCCESS_WITH_ORGANIZATION_SWITCH%%'
            LEFT JOIN s_organizations old_org ON old_org.id = so_old.organization_id
            LEFT JOIN s_organizations new_org ON new_org.id = so_new.organization_id
            WHERE so_new.user_id IN (?@)
            AND so_new.organization_id != so_old.organization_id
            ORDER BY so_new.date DESC
        ", $userIds);

        $this->db->query($sql);
        $results = $this->db->results();

        $data = [];
        if ($results) {
            foreach ($results as $row) {
                if (!isset($data[$row->user_id])) {
                    $data[$row->user_id] = $row;
                }
            }
        }

        return $data;
    }

    public function count_users($filter = array())
    {
        $id_filter = '';
        $missing_filter = '';
        $missing_status_filter = '';
        $missing_manager_filter = '';
        $missing_manager_added_to_client = '';
        $missing_date_from_filter = '';
        $missing_date_to_filter = '';
        $exclude_duplicates = '';
        $date_from_filter = '';
        $date_to_filter = '';
        $completed_filter = '';
        $keyword_filter = '';
        $search_filter = '';
        $call_status_search_filter = '';
        $continue_order_search_filter = '';
        $stage_in_contact_search_filter = '';
        $site_id_filter = '';

        if (!empty($filter['id']))
            $id_filter = $this->db->placehold("AND id IN (?@)", array_map('intval', (array)$filter['id']));

        if (isset($filter['missing_status']))
            $missing_status_filter = $this->db->placehold("AND missing_status = ?", (int)$filter['missing_status']);

        if (isset($filter['missing_manager_id']))
            $missing_manager_filter = $this->db->placehold("AND missing_manager_id IN (?@)", (array)$filter['missing_manager_id']);

        if (isset($filter['missing_manager_added_to_client']))
            $missing_manager_added_to_client = $this->db->placehold("AND missing_manager_id > 0");

        if (isset($filter['call_status_search']))
            $call_status_search_filter = $this->db->placehold("AND call_status = ?", $filter['call_status_search']);

        if (isset($filter['stage_in_contact_search']))
            $stage_in_contact_search_filter = $this->db->placehold("AND stage_in_contact = ?", $filter['stage_in_contact_search']);

        if (isset($filter['continue_order_search']))
            $continue_order_search_filter = $this->db->placehold("AND continue_order = ?", $filter['continue_order_search']);


        if (isset($filter['missing_date_from']))
            $missing_date_from_filter = $this->db->placehold("AND missing_status_date >= ?", $filter['missing_date_from']);

        if (isset($filter['missing_date_to']))
            $missing_date_to_filter = $this->db->placehold("AND missing_status_date <= ?", $filter['missing_date_to']);

        if (isset($filter['date_from']))
            $date_from_filter = $this->db->placehold("AND created >= ?", $filter['date_from']);

        if (isset($filter['date_to']))
            $date_to_filter = $this->db->placehold("AND created <= ?", $filter['date_to']);

        if (!empty($filter['completed']))
            $completed_filter = $this->db->placehold("AND additional_data_added = 1");

        if (!empty($filter['missing']))
            $missing_filter = $this->db->placehold("
                AND (
                    personal_data_added = 0 
                    OR address_data_added = 0 
                    OR accept_data_added = 0 
                    OR card_added = 0 
                    OR files_added = 0 
                    OR additional_data_added = 0 
                )
                AND (
                    (NOW() > created + INTERVAL " . intval($filter['missing']) . " SECOND  AND personal_data_added = 0)
                    OR (NOW() > personal_data_added_date + INTERVAL " . intval($filter['missing']) . " SECOND AND address_data_added = 0)
                    OR (NOW() > address_data_added_date + INTERVAL " . intval($filter['missing']) . " SECOND AND accept_data_added = 0)
                    OR (NOW() > accept_data_added_date + INTERVAL " . intval($filter['missing']) . " SECOND AND files_added = 0)
                    OR (NOW() > files_added_date + INTERVAL " . intval($filter['missing']) . " SECOND AND card_added = 0)
                    OR (NOW() > card_added_date + INTERVAL " . intval($filter['missing']) . " SECOND AND additional_data_added = 0)
                )
                AND NOT EXISTS (
                    SELECT 1 FROM s_orders so 
                    WHERE so.user_id = s_users.id
                    AND so.status IN (3, 10)
                )
                AND NOT EXISTS (
                    SELECT 1 FROM s_user_data sud 
                    WHERE sud.user_id = s_users.id
                    AND sud.key = 'is_rejected_nk'
                    AND sud.value = '1'
                )
            ");

        if (!empty($filter['exclude_duplicates'])) {
            $exclude_duplicates = $this->db->placehold("
                AND NOT EXISTS (
                    SELECT 1
                    FROM s_users u2
                    WHERE u2.id != u.id
                    AND u2.firstname = u.firstname
                    AND u2.lastname = u.lastname
                    AND u2.patronymic = u.patronymic
                    AND u2.birth = u.birth
                    AND TRIM(u.firstname) != ''
                    AND TRIM(u.lastname) != ''
                    AND TRIM(u.patronymic) != ''
                )
                AND NOT EXISTS (
                    SELECT 1
                    FROM s_users u3
                    WHERE u3.id != u.id
                    AND u3.passport_serial = u.passport_serial
                    AND u.passport_serial IS NOT NULL
                )
                AND NOT EXISTS (
                    SELECT 1
                    FROM b2p_cards bc
                    WHERE bc.user_id != u.id
                    AND bc.pan = (
                        SELECT pan FROM b2p_cards WHERE user_id = u.id AND deleted = 0 AND deleted_by_client = 0 LIMIT 1
                    )
                    AND bc.expdate = (
                        SELECT expdate FROM b2p_cards WHERE user_id = u.id AND deleted = 0 AND deleted_by_client = 0 LIMIT 1
                    )
                    AND bc.deleted = 0
                    AND bc.deleted_by_client = 0
                )
            ");
        }

        if (isset($filter['site_id'])) {
            $site_id_filter = $this->db->placehold('AND site_id = ?', $filter['site_id']);
        }

        if (isset($filter['keyword'])) {
            $keywords = explode(' ', $filter['keyword']);
            foreach ($keywords as $keyword)
                $keyword_filter .= $this->db->placehold('AND (name LIKE "%' . $this->db->escape(trim($keyword)) . '%" )');
        }

        if (!empty($filter['search'])) {
            if (!empty($filter['search']['stages'])) {
                foreach (array_unique($filter['search']['stages']) as $stage) {
                    if (isset(self::CLIENT_STAGE_COLUMN_MAP[$stage])) {
                        $col = self::CLIENT_STAGE_COLUMN_MAP[$stage];
                        $search_filter .= " AND $col = 1";
                    }
                }
            }

            if (!empty($filter['search']['user_id']))
                $search_filter .= $this->db->placehold(' AND id = ?', (int)$filter['search']['user_id']);
            if (!empty($filter['search']['created']))
                $search_filter .= $this->db->placehold(' AND DATE(created) = ?', date('Y-m-d', strtotime($filter['search']['created'])));
            if (!empty($filter['search']['fio'])) {
                $fio_filter = array();
                $expls = array_map('trim', explode(' ', $filter['search']['fio']));
                $search_filter .= $this->db->placehold(' AND (');
                foreach ($expls as $expl) {
                    $expl = $this->db->escape($expl);
                    $fio_filter[] = $this->db->placehold("(lastname LIKE '%" . $expl . "%' OR firstname LIKE '%" . $expl . "%' OR patronymic LIKE '%" . $expl . "%')");
                }
                $search_filter .= implode(' AND ', $fio_filter);
                $search_filter .= $this->db->placehold(')');
            }
            if (!empty($filter['search']['phone']))
                $search_filter .= $this->db->placehold(" AND phone_mobile LIKE '%" . $this->db->escape(str_replace(array(' ', '-', '(', ')', '+'), '', $filter['search']['phone'])) . "%'");
            if (!empty($filter['search']['email']))
                $search_filter .= $this->db->placehold(" AND email LIKE '%" . $this->db->escape($filter['search']['email']) . "%'");
            if (!empty($filter['search']['missing_manager_id']))
                $search_filter .= $this->db->placehold(' AND missing_manager_id = ?', (int)$filter['search']['missing_manager_id']);
            if (!empty($filter['search']['utm_term']))
                $search_filter .= $this->db->placehold(' AND utm_term = ?', $filter['search']['utm_term']);
        }

        $query = $this->db->placehold("
            SELECT COUNT(id) AS count
            FROM __users
            WHERE 1
                $id_filter
                $site_id_filter
                $missing_filter 
                $missing_status_filter
                $missing_manager_filter
                $missing_date_from_filter
                $missing_date_to_filter
                $date_from_filter
                $date_to_filter
                $completed_filter
                $search_filter
                $keyword_filter
                $call_status_search_filter
                $continue_order_search_filter
                $stage_in_contact_search_filter
                $missing_manager_added_to_client
        ");
        $this->db->query($query);
        $count = $this->db->result('count');

        return $count;
    }

