    private function remove_unused_agreement_keys($array)
    {
        $allowed_keys = [
            'user_id', 'lastname', 'firstname', 'patronymic', 'gender', 'birth', 'birth_place', 'phone_mobile',
            'email', 'choose_insure', 'passport_serial', 'passport_date', 'subdivision_code', 'passport_issued'
        ];

        foreach ($array as $key => $value) {
            if (!in_array($key, $allowed_keys))
                unset($array[$key]);
        }

        return $array;
    }

