    /**
     * Унифицированный способ получить баланс пользователя по конкретному займу по номеру договора.
     * Источник — 1С. Если в 1С не нашли, fallback на локальную таблицу s_user_balance по полю zaim_number.
     *
     * @param int $user_id
     * @param string|int $zaim_number Номер договора (заема)
     * @return object Нормализованный объект баланса из 1С или объект строки s_user_balance
     * @throws Exception Если $zaim_number пустой или баланс не найден в обоих источниках
     */
    public function get_user_balance_for_order(int $user_id, $zaim_number): object
    {
        if ($zaim_number === null || $zaim_number === '') {
            throw new Exception('Не передан номер договора (zaim_number)');
        }

        // Пытаемся получить баланс из 1С, строго по номеру займа (НомерЗайма == zaim_number)
        $balanceFrom1C = $this->get_user_balance_1c_normalized($user_id, function ($balance) use ($zaim_number) {
            $number = $balance->НомерЗайма ?? null;
            return (string)$number === (string)$zaim_number;
        });

        if ($balanceFrom1C) {
            return $balanceFrom1C;
        }

        // Fallback: локальная таблица s_user_balance по номеру договора
        $user_balance = $this->get_user_balance($user_id, $zaim_number);
        if ($user_balance) {
            return $user_balance;
        }

        throw new Exception('Баланс пользователя для указанного займа не найден');
    }

