    public function get_cctasks($filter = array())
    {
        $filter_from = '';
        $filter_to = '';
        $organization_filter = '';
        $organization_join = '';
        $sort = 'ub.id ASC';

        if (!empty($filter['from']))
            $filter_from = $this->db->placehold("AND ub.payment_date >= ?", $filter['from']);

        if (!empty($filter['to']))
            $filter_to = $this->db->placehold("AND ub.payment_date <= ?", $filter['to']);

        // Фильтр по организации через связь с orders
        if (!empty($filter['organization_id'])) {
            $organization_join = "
                LEFT JOIN s_contracts AS c ON c.number = ub.zaim_number
                LEFT JOIN s_orders AS o ON o.id = c.order_id
            ";
            $organization_filter = $this->db->placehold("AND o.organization_id = ?", intval($filter['organization_id']));
        }


        if (!empty($filter['sort'])) {
            switch ($filter['sort']):

                case 'payment_date_asc':
                    $sort = 'ub.payment_date ASC';
                    break;

                case 'payment_date_desc':
                    $sort = 'ub.payment_date DESC';
                    break;

                case 'number_asc':
                    $sort = 'ub.zaim_number ASC';
                    break;

                case 'number_desc':
                    $sort = 'ub.zaim_number DESC';
                    break;

                case 'status_asc':
                    $sort = 'ub.cc_status ASC';
                    break;

                case 'status_desc':
                    $sort = 'ub.cc_status DESC';
                    break;

                case 'summ_asc':
                    $sort = 'ub.ostatok_od ASC';
                    break;

                case 'summ_desc':
                    $sort = 'ub.ostatok_od DESC';
                    break;

                case 'fio_asc':
                    $sort = 'ub.client ASC';
                    break;

                case 'fio_desc':
                    $sort = 'ub.client DESC';
                    break;

                case '':
                    $sort = '';
                    break;

                case 'sum_of_columns':
                    $sort = 'total_amount DESC';
                    break;

            endswitch;
        }

        $query = $this->db->placehold("
            SELECT *,(ub.ostatok_od + ub.ostatok_percents + ub.ostatok_peni) as total_amount
            FROM __user_balance ub 
            $organization_join
            WHERE (ub.ostatok_od >= 0 OR ub.ostatok_percents >= 0 OR ub.ostatok_peni >= 0)
                $filter_from
                $filter_to
                $organization_filter
            ORDER BY $sort
        ");
//echo __FILE__.' '.__LINE__.'<br /><pre>';var_dump($query);echo '</pre><hr />';
        $this->db->query($query);
        if ($user_balances = $this->db->results()) {
            foreach ($user_balances as &$user_balance) {
                $user_balance->restructurisation = unserialize($user_balance->restructurisation);
            }
        }

        return $user_balances;
    }

