            );
    }

    /**
     * Вычисляем кол-во визитов страниц
     * @param array $filter_data
     * @return array|false
     */
    public function getTotalVisitors(array $filter_data = [])
    {
        $select = [];
        $where = [];

        $sql = "
            SELECT 
                COUNT(*) as total,
                -- {{select}}
                FROM s_visitors
            WHERE DATE(`created`) BETWEEN  '" . $filter_data['filter_date_start']->format('Y-m-d') . "' AND '" . $filter_data['filter_date_end']->format('Y-m-d') . "'
                -- {{where}}
              GROUP BY filter_date ASC
        ";


        if (!empty($filter_data['filter_group_by'])) {
            if ($filter_data['filter_group_by'] === 'day') {
                $select[] = "DATE_FORMAT(`created`, '%Y.%m.%d') as filter_date";
            } elseif ($filter_data['filter_group_by'] === 'month') {
                $select[] = "DATE_FORMAT(`created`, '%Y.%m') as filter_date";
            }
        }

        if (!empty($filter_data['filter_utm_source'])) {
            //$utm_source = $filter_data['filter_utm_source'] == 'Boostra' ? '' : $filter_data['filter_utm_source'];
            $where[] = "utm_source = '" . $filter_data['filter_utm_source'] . "'";
        }

        if (!empty($filter_data['is_main_page'])) {
            $where[] = "(LINK LIKE '%/?%' OR LINK = '/')";
        }

        $sql = strtr($sql, [
            '-- {{select}}' => !empty($select) ? implode("\n", $select) : '',
            '-- {{where}}' => !empty($where) ? "AND " . implode(" AND ", $where) : '',
        ]);

        $query = $this->db->placehold($sql);

        $this->db->query($query);
        return $this->db->results();
    }

    /**
     * Собирает статистику по воронке из CRM НК на этапах регистрации
     * @param array $filter_data
     * @return array
     * @throws Exception
     */
    public function getFunnelStatistic(array $filter_data = []): array
    {
        if (!empty($filter_data['filter_utm_source'])) {
            $where[] = $this->db->placehold("utm_source = ?", $filter_data['filter_utm_source']);
        }

        if (!empty($filter_data['filter_webmaster_id'])) {
            $where[] = $this->db->placehold("webmaster_id IN (?@)", $filter_data['filter_webmaster_id']);
        }

        if (!empty($filter_data['filter_group_by']) && $filter_data['filter_group_by'] === 'month') {
            $date_format = "%Y.%m";
        } else {
            $date_format = "%Y.%m.%d";
        }

        $results = [];
        $sqls = [];

