        $sqls['address_data'] = "SELECT 
                                            COUNT(*) as total,
DATE_FORMAT(address_data_added_date, '{{date_format}}') as date_action
FROM s_users
    JOIN s_user_data ud ON ud.user_id = id AND ud.`key` = 'is_rejected_nk' 
    WHERE (ud.`value` IS NULL or ud.`value` = 0) AND
                 DATE(address_data_added_date) BETWEEN '{{date_start}}' AND '{{date_end}}'
    $sql_address_data
                -- {{where}}
                GROUP BY date_action";

        // Страница с предварительным решением
        if (!empty($filter_data['filter_user_registered'])) {
            $sql_accept_data = "    AND DATE(address_data_added_date) = DATE(accept_data_added_date)
