DATE_FORMAT(accept_data_added_date, '{{date_format}}') as date_action
FROM s_users 
    JOIN s_user_data ud ON ud.user_id = id AND ud.`key` = 'is_rejected_nk' 
    WHERE (ud.`value` IS NULL or ud.`value` = 0) AND
                 DATE(accept_data_added_date) BETWEEN '{{date_start}}' AND '{{date_end}}'
    $sql_accept_data
                -- {{where}}
