    AND DATE(card_added_date) = DATE(additional_data_added_date)      
    AND DATE(accept_data_added_date) = DATE(additional_data_added_date)
    AND DATE(address_data_added_date) = DATE(additional_data_added_date)
    AND DATE(personal_data_added_date) = DATE(additional_data_added_date)         
    AND DATE(created) = DATE(additional_data_added_date)";
        } else {
            $sql_work_data = "";
        }
        $sqls['work_data'] = "SELECT 
                                            COUNT(*) as total,
DATE_FORMAT(additional_data_added_date, '{{date_format}}') as date_action
FROM s_users 
    JOIN s_user_data ud ON ud.user_id = id AND ud.`key` = 'is_rejected_nk' 
    WHERE (ud.`value` IS NULL or ud.`value` = 0) AND
                 DATE(additional_data_added_date) BETWEEN '{{date_start}}' AND '{{date_end}}'
                 $sql_work_data
                -- {{where}}
                GROUP BY date_action";

        foreach ($sqls as $key => $sql) {
            $sql_query = strtr($sql, [
                '{{date_format}}' => $date_format,
                '{{date_start}}' => $filter_data['filter_date_start'],
                '{{date_end}}' => $filter_data['filter_date_end'],
                '-- {{where}}' => !empty($where) ? "AND " . implode(" AND ", $where) : '',
            ]);
            $query = $this->db->placehold($sql_query);

            $this->db->query($query);
            $results_queries = $this->db->results();

            foreach ($results_queries as $results_query) {
                $results[$results_query->date_action][$key] = (int)$results_query->total;
            }
        }

        // получим ко-во заявок
        $filter_data_orders = $filter_data;
        $filter_data_orders['filter_date_start'] = new \DateTime($filter_data['filter_date_start']);
        $filter_data_orders['filter_date_end'] = new \DateTime($filter_data['filter_date_end']);

        $filter_data_orders['filter_additional_data_added_date'] = !empty($filter_data['filter_user_registered']);

        // всего, которые приняли
        $filter_data_orders['filter_date_accept'] = true;
        $orders = $this->orders->getTotalOrdersForAnalytic($filter_data_orders);
        foreach ($orders as $order) {
            $results[$order->filter_date]['orders_all'] = $order->total;
        }

        // одобрено
        $filter_data_orders['filter_date_approved'] = true;
        unset($filter_data_orders['filter_date_accept']);
        $orders = $this->orders->getTotalOrdersForAnalytic($filter_data_orders);
        foreach ($orders as $order) {
            $results[$order->filter_date]['orders_approved'] = $order->total;
        }

        // выдано
        unset($filter_data_orders['filter_status_approved']);
        $filter_data_orders['filter_date_confirm'] = true;
        $orders = $this->orders->getTotalOrdersForAnalytic($filter_data_orders);
        foreach ($orders as $order) {
            $results[$order->filter_date]['orders_issued'] = $order->total;
        }

        return $results;
    }
