    /**
     * Сбор данных для статистики по воронке ПК клиентов
     * @param array $filter_data
     * @return array|false
     * @throws Exception
     */
    public function getFunnelOldUsersStatisticSms(array $filter_data = [])
    {
        $filter_group_by = $filter_data['filter_group_by'];
        $filter_webmaster_id = implode(',', $filter_data['filter_webmaster_id']);
        $filter_date_start = $filter_data['filter_date_start'];
        $filter_date_end = $filter_data['filter_date_end'];
        $result = null;
        if ($filter_group_by == 'day') {
            $startDate = new DateTime($filter_date_start);
            $endDate = new DateTime($filter_date_end);
            $interval = new DateInterval('P1D'); // 1 day interval
            $endDate->modify('+1 day');
            $period = new DatePeriod($startDate, $interval, $endDate);

            $days = [];
            foreach ($period as $date) {
                $days[] = $date->format('Y-m-d');
            }
            $result = [];
            foreach ($days as $day) {
                $query = $this->db->placehold("
                SELECT
                    webmaster_id,
                    SUM(CASE WHEN link_date = '$day'  THEN 1 ELSE 0 END) AS total_links,
                    SUM(CASE WHEN login_date = '$day' THEN 1 ELSE 0 END) AS total_logins,
                    SUM(CASE WHEN order_date = '$day' THEN 1 ELSE 0 END) AS total_orders,
                    SUM(CASE WHEN approved_date = '$day' THEN 1 ELSE 0 END) AS total_approved,
                    SUM(CASE WHEN issue_date = '$day' THEN 1 ELSE 0 END) AS total_issued
                FROM
                    s_loan_funnel_report
                WHERE
                    webmaster_id IN ($filter_webmaster_id)
                GROUP BY
                    webmaster_id
        ");
                $this->db->query($query);
                $result[$day] = $this->db->results();

            }
        }
        else{
            $startDate = new DateTime($filter_date_start);
            $endDate = new DateTime($filter_date_end);

            $dateRanges = array();

            while ($startDate <= $endDate) {
                $startMonth = $startDate->format('Y-m-d');
                $endMonth = $startDate->format('Y-m-t');

                if ($endDate < new DateTime($endMonth)) {
                    $endMonth = $endDate->format('Y-m-d');
                }

                $dateRanges[] = array('start_month' => $startMonth, 'end_month' => $endMonth);
                $startDate->modify('first day of next month');
            }
            foreach ($dateRanges as $dateRange) {
                $start = $dateRange['start_month'];
                $end = $dateRange['end_month'];
                $query = $this->db->placehold("
                SELECT
                    webmaster_id,
                    SUM(CASE WHEN link_date BETWEEN '$start' AND '$end' THEN 1 ELSE 0 END) AS total_links,
                    SUM(CASE WHEN login_date BETWEEN '$start' AND '$end' THEN 1 ELSE 0 END) AS total_logins,
                    SUM(CASE WHEN order_date BETWEEN '$start' AND '$end' THEN 1 ELSE 0 END) AS total_orders,
                    SUM(CASE WHEN approved_date BETWEEN '$start' AND '$end' THEN 1 ELSE 0 END) AS total_approved,
                    SUM(CASE WHEN issue_date BETWEEN '$start' AND '$end' THEN 1 ELSE 0 END) AS total_issued
                FROM
                    s_loan_funnel_report
                WHERE
                    webmaster_id IN ($filter_webmaster_id)
                GROUP BY
                    webmaster_id
        ");
                $this->db->query($query);
                $date = new DateTime($start);
                $monthYear = $date->format('m-Y');
                $result[$monthYear] = $this->db->results();
            }

        }
        return $result;
    }

    /**
     * Получает баланс пользователей, в связке с заявками
     * @param array $filter_data
     * @return array|false
     */
    public function getUserBalances(array $filter_data = [])
    {
        $where = [];
        $where_order = [];

        $sql = "
            SELECT 
                ub.ostatok_od
            FROM 
                s_user_balance ub   
            LEFT JOIN s_users u ON u.id = ub.user_id
            JOIN s_orders o ON o.`1c_id` = ub.zayavka
            -- {{where_order}}
            WHERE 1
            -- {{where}}
        ";

        // активные займы
        if (!empty($filter_data['filter_active_order'])) {
            $where[] = "(ub.zaim_number != 'Нет открытых договоров' AND ub.zaim_number <> '') AND (ub.zayavka != '' AND ub.zayavka != 0)";
        }

        // порог окончательной даты платежа
        if (!empty($filter_data['filter_payment_date_end'])) {
            $where[] = $this->db->placehold("DATE(ub.payment_date) < ?", $filter_data['filter_payment_date_end']);
        }

        // даты заявки
        if (!empty($filter_data['filter_date_order'])) {
            $where_order[] = $this->db->placehold("(DATE(o.date) BETWEEN ? AND ?)", $filter_data['filter_date_order']['filter_date_start'], $filter_data['filter_date_order']['filter_date_end']);
        }

        // проверка по статусам договора
        if (!empty($filter_data['filter_order_not_1c_statuses'])) {
            $where_order[] = $this->db->placehold("o.1c_status NOT IN(?@)", $filter_data['filter_order_not_1c_statuses']);
        }

        if (!empty($filter_data['filter_order_not_statuses'])) {
            $where_order[] = $this->db->placehold("o.status NOT IN(?@)", $filter_data['filter_order_not_statuses']);
        }

        // проверка на количество пролонгаций
        if (!empty($filter_data['filter_prolongation_count_max'])) {
            $where[] = $this->db->placehold("(IFNULL(JSON_EXTRACT(u.loan_history, 
            REPLACE(JSON_UNQUOTE(JSON_SEARCH(u.loan_history, 'one', ub.zaim_number)), 
            '.number', '.prolongation_count')), 0) < ?)", $filter_data['filter_prolongation_count_max']);
        }

        // Фильтр по utm_source
        if (!empty($filter_data['filter_utm_source'])) {
            $where[] = $this->db->placehold("o.utm_source IN (?@)", $filter_data['filter_utm_source']);
        }

        // Фильтр по webmaster_id
        if (!empty($filter_data['filter_webmaster_id'])) {
            $where[] = $this->db->placehold("o.webmaster_id IN (?@)", $filter_data['filter_webmaster_id']);
        }

        $query = strtr($sql, [
            '-- {{where_order}}' => !empty($where_order) ? "AND " . implode(" AND ", $where_order) : '',
            '-- {{where}}' => !empty($where) ? "AND " . implode(" AND ", $where) : '',
        ]);

        $this->db->query($query);
        return $this->db->results();
    }

