    public function getUsersByDateInterval($start, $end)
    {
        $query = $this->db->placehold("
        SELECT 
            id,
            s_users.phone_mobile as phone,
            COALESCE(NULLIF(tz.timezone, ''), '+00:00') AS UTC
            FROM s_users 
            LEFT JOIN s_time_zones tz ON tz.time_zone_id = s_users.timezone_id
        ");
        $query .= $this->db->placehold(' WHERE 
            (personal_data_added = 0
            OR address_data_added = 0
            OR accept_data_added = 0
            OR card_added = 0
            OR files_added = 0
            OR additional_data_added = 0)
            AND (
                    (NOW() > created + INTERVAL 300 SECOND  AND personal_data_added = 0)
                    OR (NOW() > personal_data_added_date + INTERVAL 300 SECOND AND address_data_added = 0)
                    OR (NOW() > address_data_added_date + INTERVAL 300 SECOND AND accept_data_added = 0)
                    OR (NOW() > accept_data_added_date + INTERVAL 300 SECOND AND files_added = 0)
                    OR (NOW() > files_added_date + INTERVAL 300 SECOND AND card_added = 0)
                    OR (NOW() > card_added_date + INTERVAL 300 SECOND AND additional_data_added = 0)
                )');
        $query .= $this->db->placehold(' AND (missing_real_date BETWEEN  ? and ?)', $start, $end);
        $query .= $this->db->placehold(' AND (sentData = 0)');

        $this->db->query($query);

        $users = $this->db->results();

        $arr = [];
        forEach ($users as $user){
            array_push($arr,$user->id);
        }
        $arr = implode(',' ,$arr);

        $queryNew = $this->db->placehold("UPDATE s_users SET sentData = true WHERE id IN ($arr)");


        $this->db->query($queryNew);

        return $users;

    }

