    /**
     * Очищает телефон от символов и добавляет при необходимости 7 вместо 8 первой цифры
     * @param $phone
     * @param $first_number
     * @return array|string|string[]
     */
    public function clear_phone($phone, $first_number = null)
    {
        // уберем все кроме цифр
        $phone_regex = preg_replace('/[^\d]/', '', $phone);

        // добавим первую цифру
        if (!empty($first_number)) {
            $phone_formatted = preg_replace('/^(\d)?/i', $first_number, $phone_regex);
        } else {
            $phone_formatted = $phone_regex;
        }

        return $phone_formatted;
    }

    /**
     * Проверяет наличие моратория по id пользователя и организациям (опционально)
     * @param int $user_id
     * @param array $organization_ids
     * @return false|mixed
     */
    public function getMoratoriumByUserId(int $user_id, array $organization_ids = [])
    {
        $params = array($user_id);
        $sql = "SELECT
                    IF(
                        o.status = 3 AND
                        o.date + INTERVAL r.maratory DAY > NOW(),
                            1,
                            0
                    ) as moratorium,
                    o.organization_id
                FROM s_orders o
                LEFT JOIN
                    s_reasons r ON r.id = o.reason_id
                WHERE
                    o.user_id = ?";

        if (!empty($organization_ids)) {
            $sql .= $this->db->placehold(" AND o.organization_id IN (?@)", $organization_ids);
            $params = array_merge($params, $organization_ids);
        }

        $sql .= " ORDER BY
                    o.organization_id";
        
        $this->db->query($sql, ...$params);

        return $this->db->results();
    }

    public function get_users_ccprolongations($filter = array())
    {
        $date = date('Y-m-d');
        $manager_filter = '';
        $date_filter = '';
        $recall_filter = '';
        $task_filter = '';
        $vox_filter = '';
        $minus_join = '';
        $minus_filter = '';
        $missed_calls_filter = '';
        $period_filter = '';
        $call_block = "AND (calls_blacklist.unblock_day is null or calls_blacklist.unblock_day < $date or calls_blacklist.deleted_at is  not null)";
        $organization_join = '';
        $organization_filter = '';
        if (isset($filter['manager_id']))
            $manager_filter = $this->db->placehold("AND s_pr_tasks.manager_id   = ?", $filter['manager_id']);

        if (isset($filter['task_id']))
            $task_filter = $this->db->placehold("AND s_pr_tasks.id = ?", $filter['task_id']);

        if (isset($filter['date']))
            $date_filter = $this->db->placehold("AND s_pr_tasks.task_date = ?",  $filter['date']);

        // Поддержка диапазона дат
        if (isset($filter['task_date_from']) && isset($filter['task_date_to'])) {
            $date_filter = $this->db->placehold("AND s_pr_tasks.task_date BETWEEN ? AND ?", $filter['task_date_from'], $filter['task_date_to']);
        } elseif (isset($filter['task_date_from'])) {
            $date_filter = $this->db->placehold("AND s_pr_tasks.task_date >= ?", $filter['task_date_from']);
        } elseif (isset($filter['task_date_to'])) {
            $date_filter = $this->db->placehold("AND s_pr_tasks.task_date <= ?", $filter['task_date_to']);
        }

        if (isset($filter['recall_start']) && isset($filter['recall_end']))
            $recall_filter = $this->db->placehold("AND s_pr_tasks.recall_date BETWEEN  ? and ?",  $filter['recall_start'],$filter['recall_end']);

        if (isset($filter['vox_call']))
            $vox_filter = $this->db->placehold("AND s_pr_tasks.vox_call = false");

        if (isset($filter['minus']) && ($filter['minus'] == '-4' || $filter['minus'] == '-2')) {
            $period = '-5';
            if ($filter['minus'] == '-2'){
                $period = '-3';
            }
            $minus_join = $this->db->placehold("JOIN s_pr_tasks AS t on  (s_pr_tasks.user_id = t.user_id and t.period = '$period' and t.status != 2)");
        }
        if (isset($filter['missed_calls'])) {
            $missed_calls_filter = $this->db->placehold("AND s_pr_tasks.status = 2 AND close = 0 AND prolongation = 0");
        }
        if (isset($filter['period'])) {
            $period_filter = $this->db->placehold("AND s_pr_tasks.period = ?",  'zero');
        }
        if (!empty($filter['organization_id'])) {
            // Используем несколько способов связи:
            // 1. Через контракт (c.number = s_pr_tasks.number)
            // 2. Через менеджера (managers_schedule.organization_id) - для задач, созданных заранее
            $organization_join = "
                LEFT JOIN s_contracts AS c ON c.number = s_pr_tasks.number
                LEFT JOIN s_orders AS o1 ON o1.id = c.order_id
                LEFT JOIN managers_schedule ON managers_schedule.manager_id = s_pr_tasks.manager_id 
                    AND managers_schedule.date = s_pr_tasks.task_date
            ";
            $organization_filter = $this->db->placehold(" AND (o1.organization_id = ? OR managers_schedule.organization_id = ?)", (int)$filter['organization_id'], (int)$filter['organization_id']);
        }
        $query = $this->db->placehold('
                Select CONCAT(s_users.firstname, " ", s_users.lastname, " ", s_users.patronymic) as name,phone_mobile as phone,COALESCE(NULLIF(s_time_zones.timezone, ""), "+00:00") AS UTC,s_user_balance.prolongation_amount,s_user_balance.zaim_summ,s_user_balance.overdue_debt_od_IL,s_user_balance.overdue_debt_percent_IL,s_user_balance.next_payment_od,s_user_balance.next_payment_percent,s_user_balance.loan_type,s_pr_tasks.number,s_pr_tasks.manager_id from s_pr_tasks
                '.$minus_join.'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
                left JOIN s_users on s_users.id = s_pr_tasks.user_id
                left join s_user_balance on s_pr_tasks.user_balance_id = s_user_balance.id
                '.$organization_join.'
                left join s_time_zones on s_users.timezone_id = s_time_zones.time_zone_id 
                LEFT JOIN calls_blacklist ON s_users.id = calls_blacklist.user_id
                where 1 '.
            $manager_filter.' '.
            $date_filter.' '.
            $recall_filter.' '.
            $task_filter.' '.
            $vox_filter.' '.
            $minus_filter.' '.
            $missed_calls_filter.' '.
            $period_filter.' '.
            $minus_filter.' '.
            $organization_filter.' '.
            $call_block
        );
        $this->db->query($query);
        return $this->db->results();
    }

