    public function update_mark_day(int $user_id)
    {
        $date = date('Y-m-d');
        $query = $this->db->placehold("
            UPDATE s_users
            SET last_mark = ?
            WHERE id = ?",$date,$user_id);

        $this->db->query($query);
    }

    public function get_user_balance_1c($uid_1c, $log = true) {

        $site_id = $this->users->get_site_id_by_user_1c_id($uid_1c);
        $inn_arr =  $this->organizations->get_inns_by_site_id($site_id);
        if (empty($inn_arr)){ 
            return false;
        }

        if (!empty($uid_1c)) {
            $z = new stdClass();
            $z->UID = $uid_1c;
            $z->Пароль = $this->settings->api_password;
            $z->Partner = 'Boostra';
            $z->ArrayINN = json_encode($inn_arr, false);

//    echo __FILE__.' '.__LINE__.'<br /><pre>';var_dump($z);echo '</pre><hr />';
            $uid_client = new SoapClient($this->config->url_1c . $this->config->work_1c_db . "/ws/WebLK.1cws?wsdl");
            $returned = $uid_client->__soapCall('GetLKINN', array($z));
            if (!empty($log))
                $this->logging(__METHOD__, $this->config->url_1c . $this->config->work_1c_db . '/ws/WebLK.1cws?wsdl GetLKINN', (array) $z, (array) $returned);

            return $returned;
        } else
            return false;
    }

    /**
     * Получить нормализованный баланс пользователя из 1С.
     * Если передан фильтр, выбирается первый баланс, удовлетворяющий условию.
     * Иначе берется первый из списка.
     *
     * @param int $user_id
     * @param callable|null $filterCallback Принимает элемент массива балансов из 1С и возвращает bool
     * @return object|null Нормализованный объект баланса или null, если ничего не найдено
     */
    public function get_user_balance_1c_normalized(int $user_id, ?callable $filterCallback = null): ?object
    {
        $userUid = $this->getUserUidById($user_id);
        if (empty($userUid)) {
            return null;
        }

        $site_id = $this->users->get_site_id_by_user_id($user_id);
        if (empty($site_id)) {
            return null;
        }

        $balances = $this->soap->get_user_balances_array_1c($userUid, $site_id);
        if (empty($balances)) {
            return null;
        }

        if ($filterCallback === null) {
            $firstBalance = (object)current($balances);
            if (empty($firstBalance)) {
                return null;
            }
            return $this->make_up_user_balance($user_id, $firstBalance);
        }

        $filteredBalances = array_filter($balances, $filterCallback);
        if (empty($filteredBalances)) {
            return null;
        }

        $balance = (object)array_shift($filteredBalances);
        return $this->make_up_user_balance($user_id, $balance);
    }

    /** 
     * Обновляем инфу об активном займе клиента на основании инфы, которую мы получили из 1с
     * @return array|false Массив займов из 1С или false при ошибке
     */
    public function updateUserBalanceAccordingTo1c(object $user)
    {
        $rzs = $this->organizations->get_organization($this->organizations::RZS_ID);
        $userBalances = $this->soap->get_user_balances_array_1c($user->UID, $user->site_id);
        if (!$userBalances) {
            return false;
        }

        $userBalance1c = null;
        foreach ($userBalances as $ub) {
            if ($rzs->inn == $ub['ИНН']) {
                $userBalance1c = $ub;
                break;
            }
        }
        if (empty($userBalance1c)) {
            $userBalance1c = reset($userBalances);
        }

        $userBalance1c = $this->users->make_up_user_balance($user->id, (object)$userBalance1c);
        $userBalance = $this->users->get_user_balance($user->id);

        if (empty($userBalance)) {
            $this->users->add_user_balance($userBalance1c);
        } else {
            $this->users->update_user_balance($userBalance->id, $userBalance1c);
        }

        return $userBalances;
    }

    /**
     * Извлекает займ из истории займов пользователя по идентификатору.
     *
     * @param object $userInfo Информация о пользователе, содержащая историю займов.
     * @param int $loanId Идентификатор займа, который необходимо извлечь.
     * @return object|null Объект займа или null, если займ не найден.
     */
    public function getLoanFromHistory($userInfo, $loanId)
    {
        foreach ($userInfo->loan_history as $loan) {
            if ($this->isLoanMatch($loan, $loanId)) {
                return $loan;
            }
        }
        
        return null;
    }

    /**
     * Проверяет соответствие идентификатора займа номеру контракта.
     *
     * @param object $order Объект займа.
     * @param int $orderId Идентификатор займа для проверки.
     * @return bool True, если идентификатор соответствует номеру контракта.
     */
    private function isLoanMatch($loan, $loanId)
    {
        $loanIdStr = (string) $loanId;
        $numberParts = explode('-', $loan->number);
        $numberSuffix = end($numberParts);

        return $numberSuffix === $loanIdStr;
    }
    
    /**
     * Обрабатывает данные договора и обновляет информацию об ответственном коллекторе.
     *
     * @param object $userInfo Информация о пользователе, содержащая историю займов.
     * @param array $contractDataList Список данных договора, полученных из внешнего сервиса.
     * @return bool Возвращает true, если была обновлена информация об ответственном коллекторе, иначе false.
     */
    private function processContractData($userInfo, $contractDataList)
    {
        // Создаем индекс для быстрого поиска
        $loansByNumber = [];
        foreach ($userInfo->loan_history as $loan) {
            $loansByNumber[$loan->number] = $loan;
        }

        $updated = false;
        foreach ($contractDataList as $contractData) {
            if (empty($contractData['НомерДоговора']) || empty($contractData['Ответственный'])) {
                continue;
            }

            $number = $contractData['НомерДоговора'];
            if (isset($loansByNumber[$number])) {
                $loansByNumber[$number]->responsible_collector = $contractData['Ответственный'];
                $updated = true;
            }
        }

        return $updated;
    }
    
    public function findDuplicates($user)
    {
        if (is_array($user))
            $user = (object)$user;
        if (is_string($user) || is_numeric($user))
            $user = $this->users->get_user((int)$user);
        if (empty($user->id))
            $user->id = $user->user_id;

        $duplicates = [];

        // Совпадения по ФИО + ДР
        $fio_duplicates = $this->users->get_users([
            'column' => [
                'firstname' => $user->firstname,
                'lastname' => $user->lastname,
                'patronymic' => $user->patronymic,
                'birth' => $user->birth
            ]
        ]);
        if (!empty($fio_duplicates)) {
            foreach ($fio_duplicates as $duplicate) {
                if ($duplicate->id == $user->id)
                    continue;
                $duplicates[$duplicate->id][] = 'ФИО+ДР';
            }
        }

        // Совпадения по номеру карты
        $user_cards = $this->best2pay->get_cards([
            'user_id' => $user->id
        ]);
        if (!empty($user_cards)) {
            $cards_pan_expdate = [];
            foreach ($user_cards as $user_card) {
                if (empty($user_card->deleted) && empty($user_card->deleted_by_client)) {
                    $cards_pan_expdate[] = [$user_card->pan, $user_card->expdate];
                }
            }

            if (!empty($cards_pan_expdate)) {
                // Получаем строку вида
                // ('123456******1234', '01/2024'), ('123456******1234', '01/2024'
                $conditions = implode(", ", array_map(function($card) {
                    return "('" . $card[0] . "', '" . $card[1] . "')";
                }, $cards_pan_expdate));

                $this->db->query("SELECT * FROM b2p_cards WHERE user_id != ? AND deleted = 0 AND deleted_by_client = 0 AND (pan, expdate) IN ($conditions)", $user->id);
                $card_duplicates = $this->db->results();
                if (!empty($card_duplicates)) {
                    foreach ($card_duplicates as $card) {
                        $duplicates[$card->user_id][] = 'Карта ' . $card->pan;
                    }
                }
            }
        }

        // Телефон
        $phone_duplicates = $this->users->get_users([
            'column' => [
                'phone_mobile' => $user->phone_mobile
            ]
        ]);
        if (!empty($phone_duplicates)) {
            foreach ($phone_duplicates as $duplicate) {
                if ($duplicate->id == $user->id)
                    continue;
                $duplicates[$duplicate->id][] = 'Телефон';
            }
        }

        // Email
        if (!empty($user->email)) {
            $email_duplicates = $this->users->get_users([
                'column' => [
                    'email' => $user->email
                ]
            ]);
            if (!empty($email_duplicates)) {
                foreach ($email_duplicates as $duplicate) {
                    if ($duplicate->id == $user->id)
                        continue;
                    $duplicates[$duplicate->id][] = 'Почта';
                }
            }
        }

        // Паспорт
        if (!empty($user->passport_serial)) {
            $passport_duplicates = $this->users->get_users([
                'column' => [
                    'passport_serial' => $user->passport_serial
                ]
            ]);
            if (!empty($passport_duplicates)) {
                foreach ($passport_duplicates as $duplicate) {
                    if ($duplicate->id == $user->id)
                        continue;
                    $duplicates[$duplicate->id][] = 'Паспорт';
                }
            }
        }

        // IP
        $this->db->query("SELECT DISTINCT o1.user_id, o1.ip 
                          FROM s_orders o1 
                          WHERE o1.user_id != ? 
                          AND o1.ip IN (
                              SELECT DISTINCT o2.ip 
                              FROM s_orders o2 
                              WHERE o2.user_id = ? 
                              AND o2.ip != '127.0.0.1'
                          )
                          ORDER BY o1.user_id DESC LIMIT 20", $user->id, $user->id);
        $ip_duplicates = $this->db->results();
        if (!empty($ip_duplicates)) {
            foreach ($ip_duplicates as $duplicate) {
                $duplicates[$duplicate->user_id][] = 'IP ' . $duplicate->ip;
            }
        }

        return $duplicates;
    }

